using System;
using System.Diagnostics;
using System.IO;

public void GeneratePdf(string htmlFile, string pdfOutput, string pageSize = "A4", string orientation = "Portrait")
{
    var wkhtmltopdfPath = "/path/to/wkhtmltopdf"; // Replace with the path to your wkhtmltopdf executable
    var arguments = $"{wkhtmltopdfPath} {htmlFile} -O {pageSize}x{orientation} {pdfOutput}";

    Process.Start(new ProcessStartInfo
    {
        FileName = "cmd.exe",
        Arguments = arguments,
        RedirectStandardOutput = true,
        UseShellExecute = false,
        CreateNoWindow = true
    });
}